3	import { runScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // --- QUOTE: empty and base premiums ---
7	  it.todo("empty item list yields premium of 5G (processing fee only)");
8	  it.todo("quote for a single sword yields 105G (100G base + 5G fee)");
9	  it.todo("quote for a single amulet yields 65G (60G base + 5G fee)");
