11	  it.todo("quote for a single potion yields 45G (40G base + 5G fee)");
12	
13	  // --- QUOTE: components and blocks ---
14	  it.todo("quote for a single rune yields 30G (25G base + 5G fee)");
15	  it.todo("quote for 2 runes yields 55G (50G base + 5G fee)");
16	  it.todo("quote for 3 runes applies block: 65G (60G base + 5G fee)");
17	  it.todo("quote for 4 runes does not apply block: 105G (100G base + 5G fee)");
18	  it.todo("quote for 7 runes yields 180G (175G base premium per spec + 5G fee)");
19	  it.todo("quote for 2 runes + 1 moonstone yields 80G base premium (75G base + 5G fee = 80G; no block — different types)");
20	  it.todo("quote for 3 runes + 3 moonstones applies two separate blocks: 125G (120G base + 5G fee)");
21	
22	  // --- QUOTE: item-specific modifiers ---
23	  it.todo("cursed sword adds 50% surcharge to that item's base premium");
24	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge");
25	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
26	  it.todo("cursed sword with enchantment 5 stacks both surcharges");
27	
28	  // --- QUOTE: policy-wide modifiers ---
29	  it.todo("first insurance adds 10% surcharge per item to policy base premium");
30	  it.todo("long-standing customer (2 years) gets 20% loyalty discount on policy base premium");
31	  it.todo("customer with exactly 2 years receives loyalty discount (threshold)");
32	  it.todo("customer with less than 2 years does not receive loyalty discount");
33	  it.todo("follow-up contract (second quote) gets 15% discount");
34	
35	  // --- QUOTE: integration examples from spec ---
36	  it.todo("newcomer with cursed sword (steel, enchantment 3) -> premium 165G");
37	  it.todo("multi-item: cursed sword + plain amulet -> 210G before policy modifiers and fee");
38	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7) -> 160G");
39	
40	  // --- QUOTE: rounding ---
41	  it.todo("premium of 197.5G rounds up to 198G (in MHPCO's favor)");
42	
43	  // --- QUOTE: rejections ---
44	  it.todo("quote with unknown item type causes CLI to exit non-zero with no results on stdout");
45	
46	  // --- CLAIM: standard reimbursement ---
47	  it.todo("regular sword (steel, enchantment 3), damage 500G -> payout 400G");
48	  it.todo("damage to a rune (insurance 250G), damage 200G -> payout 100G");
49	
50	  // --- CLAIM: deductible per damage event ---
51	  it.todo("dragon attack damages sword (500G) and amulet (300G) -> payout 600G (deductible per item)");
52	
53	  // --- CLAIM: enchantment threshold ---
54	  it.todo("steel sword, enchantment 9, damage 1000G -> payout 400G (50% then deductible)");
55	
56	  // --- CLAIM: dragon material ---
57	  it.todo("dragon-material sword, enchantment 5, damage 800G -> payout 700G (full reimbursement, deductible)");
58	  it.todo("dragon-material sword with enchantment 8 + 1000G damage -> payout 400G (high-ench applies, deductible)");
59	  it.todo("dragon-material sword, enchantment 9, damage 1000G -> payout 400G (50% rule wins, then deductible)");
60	
61	  // --- CLAIM: rounding ---
62	  it.todo("payout calculation of 350.5G rounds down to 350G");
63	
64	  // --- CLAIM: cap and multiple items ---
65	  it.todo("policy with two swords -> insurance sum 2000G, cap 4000G");
66	  it.todo("two sword damages on a two-sword policy -> each entry has its own deductible");
67	  it.todo("cursed sword has cap 2000G (based on unmodified insurance value, not modified premium)");
68	  it.todo("policy with sword + 3 runes -> insurance sum 1750G (block discount affects only premium)");
69	
70	  // --- CLAIM: cap exhaustion across successive claims ---
71	  it.todo("sword (cap 2000G), first claim 1500G -> payout 1400G, remaining cap 600G");
72	  it.todo("sword (cap 2000G), second claim 1500G after first -> payout 600G, remaining cap 0G");
