it("empty item list yields premium of 5G (processing fee only)", () => {
  const scenario = {
    customer: { yearsWithMHPCO: 0 },
    steps: [{ op: "quote", items: [] }],
  };
  const result = runScenario(scenario);
  expect(result.results[0].premium).toBe(5);
});

